#include <stdio.h>
#include <stdlib.h>

int *alociraj_niz(int broj_el) {
return (int*)calloc(broj_el, sizeof(int));
}


void oslobodi_niz(int *niz) {
free(niz);
}

int nadji_maks(int* niz, int n) {
int maks = niz[0];
for (int i = 1; i < n; i++) {
if (niz[i] > maks) {
maks = niz[i];
}
}
return maks;
}

int main() {
int n;

printf("Unesite broj elemenata niza: ");
scanf("%d", &n);

int* niz = alociraj_niz(n);
if (niz == NULL) {
printf("Alokacija nije uspjela.\n");
return 1;
}

for (int i = 0; i < n; i++) {
printf("niz[%d] = ", i);
scanf("%d", &niz[i]);
}

int maks = nadji_maks(niz, n);
printf("Maksimalni element u nizu je: %d\n", maks);

oslobodi_niz(niz);
return 0;
}

#include <stdio.h>
#include <stdlib.h>

int *alociraj_niz(int broj_el) {
int *pok = (int*)malloc(sizeof(int) * broj_el);
return pok;
}

void oslobodi_niz(int *niz) {
free(niz);
}

int main() {
int n = 0;

printf("Unesite broj elemenata niza: ");
scanf("%d", &n);

int *niz = alociraj_niz(n);

if (!niz) { /* kao i: if (niz == NULL) */
printf("Alokacija nije uspjela!\n");
return 1;
}

printf("Unesite elemente niza:\n");
int a = 0;
for (a = 0; a < n; a++) {
printf("niz[%i] = ", a);
scanf("%i", &niz[a]);
}

printf("Uneseni niz naopako ispisan:\n");
for (a = n - 1; a >= 0; a--) {
printf("%i ", niz[a]);
}
printf("\n");

/* moramo osloboditi zauzetu memoriju */
oslobodi_niz(niz);

return 0;
}

#include <stdio.h>
#include <stdlib.h>

struct Student {
char ime[30];
int bodovi;
};

struct Student* alociraj_studente(int n) {
return (struct Student*)calloc(n, sizeof(struct Student));
}

void oslobodi_studente(struct Student* s) {
free(s);
}

int indeks_maks_bodova(struct Student* s, int n) {
int max_i = 0;
for (int i = 1; i < n; i++) {
if (s[i].bodovi > s[max_i].bodovi) {
max_i = i;
}
}
return max_i;
}

int main() {
int n;

printf("Unesite broj studenata: ");
scanf("%d", &n);

struct Student* studenti = alociraj_studente(n);
if (studenti == NULL) {
printf("Alokacija nije uspjela.\n");
return 1;
}

for (int i = 0; i < n; i++) {
printf("Ime studenta %d: ", i + 1);
scanf("%s", studenti[i].ime);

printf("Bodovi: ");
scanf("%d", &studenti[i].bodovi);
}

int idx = indeks_maks_bodova(studenti, n);

printf("\nStudent sa najvise bodova:\n");
printf("Ime: %s\n", studenti[idx].ime);
printf("Bodovi: %d\n", studenti[idx].bodovi);

oslobodi_studente(studenti);
return 0;
}

