/* Funkcija racuna sredinu i upisuje je preko pokazivaca */
void sredina(const struct Tacka* t1,
const struct Tacka* t2,
struct Tacka* rezultat) {
rezultat->x = (t1->x + t2->x) / 2;
rezultat->y = (t1->y + t2->y) / 2;
}

int main() {
struct Tacka a = {2.0, 4.0};
struct Tacka b = {6.0, 8.0};
struct Tacka c;
sredina(&a, &b, &c);

printf("Sredina: (%.1f, %.1f)\n", c.x, c.y);
return 0;
}

