#include <stdio.h>
#include <string.h>

struct Student {
char ime[20];
char prezime[20];
int indeks;
int ocjene[5];
float prosjek;
};

/* racunanje prosjeka */
float izracunajProsjek(int ocjene[], int brojOcjena) {
int suma = 0, i;
for (i = 0; i < brojOcjena; i++) {
suma += ocjene[i];
}
return (float)suma / brojOcjena;
}

int main() {
int brojStudenata = 3;
int brojOcjena = 5;

struct Student studenti[brojStudenata];
int i, j;

/* unos podataka */
for (i = 0; i < brojStudenata; i++) {
printf("\nStudent %d\n", i + 1);

printf("Ime: ");
scanf("%s", studenti[i].ime);

printf("Prezime: ");
scanf("%s", studenti[i].prezime);

printf("Indeks: ");
scanf("%d", &studenti[i].indeks);

printf("Unesite %d ocjena:\n", brojOcjena);
for (j = 0; j < brojOcjena; j++) {
printf("Ocjena %d: ", j + 1);
scanf("%d", &studenti[i].ocjene[j]);
}

studenti[i].prosjek = izracunajProsjek(studenti[i].ocjene, brojOcjena);
}

/* selection sort po prosjeku */
for (i = 0; i < brojStudenata - 1; i++) {
int minIndex = i;

for (j = i + 1; j < brojStudenata; j++) {
if (studenti[j].prosjek < studenti[minIndex].prosjek) {
minIndex = j;
}
}

if (minIndex != i) {
struct Student temp = studenti[i];
studenti[i] = studenti[minIndex];
studenti[minIndex] = temp;
}
}

/* ispis nakon sortiranja */
printf("Studenti sortirani po prosjeku: \n");
for (i = 0; i < brojStudenata; i++) {
printf("%s %s | indeks: %d | prosjek: %.2f\n",
studenti[i].ime,
studenti[i].prezime,
studenti[i].indeks,
studenti[i].prosjek);
}

return 0;
}

#include <stdio.h>
#include <string.h>

struct Student {
char ime[20];
char prezime[20];
int indeks;
int ocjene[5];
float prosjek;
};

/* prosjek: prima pokazivac na niz ocjena */
float izracunajProsjek(int *ocjene, int brojOcjena) {
int suma = 0, i;
for (i = 0; i < brojOcjena; i++) {
suma += *(ocjene + i);            //pokazivacki pristup elementima
}
return (float)suma / brojOcjena;
}

int main() {
int brojStudenata = 3;
int brojOcjena = 5;

struct Student studenti[3];
struct Student *p = studenti;         //pokazivac na niz struktura
int i, j;

/*unos podataka (preko pokazivaca na studenta) */
for (i = 0; i < brojStudenata; i++) {
printf("\nStudent %d\n", i + 1);
printf("Ime: ");
scanf("%s", (p + i)->ime);

printf("Prezime: ");
scanf("%s", (p + i)->prezime);

printf("Indeks: ");
scanf("%d", &((p + i)->indeks));

printf("Unesite %d ocjena:\n", brojOcjena);
for (j = 0; j < brojOcjena; j++) {
printf("Ocjena %d: ", j + 1);
scanf("%d", &(*((p + i)->ocjene + j)));   //pokazivac na niz unutar strukture
}

(p + i)->prosjek = izracunajProsjek((p + i)->ocjene, brojOcjena);
}

/* selection sort po prosjeku (sve preko p) */
for (i = 0; i < brojStudenata - 1; i++) {
int minIndex = i;

for (j = i + 1; j < brojStudenata; j++) {
if ((p + j)->prosjek < (p + minIndex)->prosjek) {
minIndex = j;
}
}

if (minIndex != i) {
struct Student temp = *(p + i);
*(p + i) = *(p + minIndex);
*(p + minIndex) = temp;
}
}

/* ispis nakon sortiranja */
printf("\nStudenti sortirani po prosjeku:\n");
for (i = 0; i < brojStudenata; i++) {
printf("%s %s | indeks: %d | prosjek: %.2f\n",
(p + i)->ime,
(p + i)->prezime,
(p + i)->indeks,
(p + i)->prosjek);
}

return 0;
}

#include <stdio.h>

struct Proizvod {
char naziv[20];
float cijena;
};

void sortirajPoCijeni(struct Proizvod *p, int n) {
for (int i = 0; i < n - 1; i++) {
int minIndex = i;

for (int j = i + 1; j < n; j++) {
if ((p + j)->cijena < (p + minIndex)->cijena) {
minIndex = j;
}
}

if (minIndex != i) {
struct Proizvod temp = *(p + i);
*(p + i) = *(p + minIndex);
*(p + minIndex) = temp;
}
}
}

int main() {
struct Proizvod proizvodi[4] = {
{"Hljeb", 2.0},
{"Mlijeko", 2.5},
{"Sir", 5.0},
{"Jaja", 3.0}
};

int n = 4;
struct Proizvod *p = proizvodi;

sortirajPoCijeni(p, n);

printf("Proizvodi sortirani po cijeni:\n");
for (int i = 0; i < n; i++) {
printf("%s - %.2f\n", (p + i)->naziv, (p + i)->cijena);
}

return 0;
}

