#include <stdio.h>


/* Sadrzaj datoteke:

Ovo je primjer tekstualne datoteke.
Koristi se za demonstraciju rada sa fseek i ftell funkcijama.
Pomjeranje kursora omogucava citanje sa razlicitih pozicija.

*/


int main() {
FILE *file = fopen("podaci.txt", "r+");   /* read-update mod */
if (file == NULL) {
printf("Greska: ne mogu otvoriti podaci.txt\n");
return 1;
}

/* 1) pomjeramo kursor na kraj datoteke */
fseek(file, 0, SEEK_END);

/* 2) ftell daje trenutnu poziciju (najcesce broj bajtova = velicina datoteke) */
long velicina = ftell(file);
printf("Velicina datoteke (ftell na kraju): %ld\n", velicina);

/* 3) pomjeramo kursor na pocetak datoteke */
fseek(file, 0, SEEK_SET);

/* 4) procitaj i ispisi prvih N znakova */
int N = 20;
int c;
int brojac = 0;

printf("Prvih %d znakova: ", N);
while (brojac < N && (c = fgetc(file)) != EOF) {
printf("%c", c);
brojac++;
}
printf("\n");

/* 5) ispisujemo trenutnu poziciju nakon citanja */
long pozicija = ftell(file);
printf("Pozicija kursora nakon citanja: %ld\n", pozicija);

fclose(file);
return 0;
}

#include <stdio.h>

int main() {
FILE *f = fopen("podaci.txt", "r+");
if (f == NULL) {
printf("Greska pri otvaranju datoteke.\n");
return 1;
}

/* odredi velicinu datoteke */
fseek(f, 0, SEEK_END);
long velicina = ftell(f);

/* postavi kursor na sredinu datoteke */
long sredina = velicina / 2;
fseek(f, sredina, SEEK_SET);

/* ispis pozicije kursora na sredini */
printf("Pozicija kursora na sredini: %ld\n", ftell(f));

/* procitaj i ispisi naredna tri znaka */
printf("Tri znaka od sredine: ");
for (int i = 0; i < 3; i++) {
int c = fgetc(f);
if (c == EOF)
break;
printf("%c", c);
}
printf("\n");

/* ispis pozicije kursora nakon citanja */
printf("Pozicija kursora nakon citanja: %ld\n", ftell(f));

fclose(f);
return 0;
}

#include <stdio.h>
#include <stdlib.h>

struct Osoba {
